{"type": "email", "id": "email_001", "subject": "Quarterly Budget Review", "from": "michael.williams@elexionautomotive.com", "from_name": "Michael Williams", "to": ["sofia.rodriguez@elexionautomotive.com", "jack.martin@elexionautomotive.com"], "cc": ["linda.garcia@elexionautomotive.com"], "date": "2022-08-15 10:30:00", "body": "Dear team, 

