{"type": "email", "id": "email_002", "subject": "New Employee Onboarding", "from": "elizabeth.brown@elexionautomotive.com", "from_name": "Elizabeth Brown", "to": ["sofia.rodriguez@elexionautomotive.com"], "cc": [], "date": "2022-08-16 09:15:00", "body": "Hi Sofia, 

