{"type": "email", "id": "email_005", "subject": "Upcoming Industry Conference", "from": "emily.johnson@elexionautomotive.com", "from_name": "Emily Johnson", "to": ["sofia.rodriguez@elexionautomotive.com"], "cc": [], "date": "2022-08-19 11:30:00", "body": "Hi Sofia, 

